head.b:skin:
/* ═══════════════════════════════════
   TOOLSHUB PRO — DESIGN SYSTEM
═══════════════════════════════════ */
:root{
  --bg:#0b0f1a;--bg2:#111827;--s1:#1a2234;--s2:#1e2a3e;--s3:#243147;--s4:#2c3d58;
  --br:#2e3f5c;--br2:#3a4f6e;
  --a:#3b82f6;--a2:#6366f1;--a3:#22d3ee;--g:#10b981;--r:#ef4444;--y:#f59e0b;
  --tx:#e8edf5;--t2:#94a3b8;--t3:#4a6080;--t4:#2d3d55;
  --grad:linear-gradient(135deg,#3b82f6 0%,#6366f1 50%,#22d3ee 100%);
  --shadow:0 4px 24px rgba(0,0,0,.4);
  --nav-h:64px;
  --f-display:'Syne',sans-serif;
  --f-body:'DM Sans',sans-serif;
  --r1:10px;--r2:16px;--r3:22px;
  --ease:cubic-bezier(.22,1,.36,1);
}
body.light-mode{
  --bg:#f0f4f8;--bg2:#fff;--s1:#fff;--s2:#f5f8fc;--s3:#edf2f7;--s4:#e2e8f0;
  --br:#d1dce9;--br2:#bac8d8;--a:#2563eb;--a2:#4f46e5;--a3:#0891b2;
  --tx:#0f1f36;--t2:#334e68;--t3:#627d98;--t4:#9fb3c8;
  --shadow:0 4px 20px rgba(0,0,0,.08);
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{font-family:var(--f-body);background:var(--bg);color:var(--tx);font-size:15px;line-height:1.65;-webkit-font-smoothing:antialiased;overflow-x:hidden;transition:background-color .3s ease,color .3s ease}
a{color:var(--a);text-decoration:none;transition:color .2s}
img{max-width:100%;height:auto;display:block}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg)}::-webkit-scrollbar-thumb{background:var(--br2);border-radius:3px}
.wrap{max-width:1200px;margin:0 auto;padding:0 24px}
.wrap-sm{max-width:880px;margin:0 auto;padding:0 24px}

/* ━━ HEADER ━━ */
#lp-header{position:fixed!important;top:0!important;left:0;right:0;width:100%;z-index:3000!important;height:var(--nav-h);background:rgba(11,15,26,.93);backdrop-filter:blur(20px) saturate(180%);-webkit-backdrop-filter:blur(20px) saturate(180%);border-bottom:1px solid rgba(255,255,255,.06);transition:box-shadow .3s}
body{padding-top:var(--nav-h)}
body.light-mode #lp-header{background:rgba(255,255,255,.94);border-bottom-color:rgba(0,0,0,.07)}
#lp-header.scr{box-shadow:0 8px 40px rgba(0,0,0,.25)}
body.light-mode #lp-header.scr{box-shadow:0 8px 32px rgba(15,23,42,.1)}
.hdr{display:flex;align-items:center;height:var(--nav-h);gap:0}
.logo{display:flex;align-items:center;gap:10px;text-decoration:none;flex-shrink:0}
.logo-ico{width:38px;height:38px;border-radius:11px;background:linear-gradient(135deg,#1e40af,#312e81);border:1px solid rgba(99,102,241,.35);display:flex;align-items:center;justify-content:center;font-size:19px;box-shadow:0 2px 12px rgba(59,130,246,.3)}
.logo-txt{font-family:var(--f-display);font-size:19px;font-weight:800;letter-spacing:-.5px;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;white-space:nowrap}
/* NAV */
.lp-nav{flex:1;display:flex;align-items:center;justify-content:center;gap:2px}
.ni{position:relative}
.nl{display:flex;align-items:center;gap:5px;padding:8px 13px;border-radius:9px;font-size:13.5px;font-weight:500;color:var(--t2);text-decoration:none;transition:all .18s;white-space:nowrap}
.nl svg{width:11px;height:11px;fill:none;stroke:currentColor;stroke-width:2.5;transition:transform .2s}
.nl:hover,.ni:hover>.nl{color:var(--a);background:var(--s3)}
.ni:hover>.nl svg{transform:rotate(180deg)}
.dd{position:absolute;top:calc(100% + 8px);left:50%;transform:translateX(-50%) translateY(8px);background:var(--s1);border:1px solid rgba(99,102,241,.2);border-radius:18px;padding:0;box-shadow:0 32px 80px rgba(0,0,0,.55),0 8px 24px rgba(0,0,0,.25),inset 0 1px 0 rgba(255,255,255,.06);opacity:0;visibility:hidden;pointer-events:none;transition:all .25s cubic-bezier(.4,0,.2,1);z-index:500}
.dd::before{content:'';position:absolute;top:-6px;left:50%;transform:translateX(-50%) rotate(45deg);width:11px;height:11px;background:var(--s1);border-left:1px solid rgba(99,102,241,.2);border-top:1px solid rgba(99,102,241,.2)}
.ni:hover .dd{opacity:1;visibility:visible;pointer-events:auto;transform:translateX(-50%) translateY(0)}
/* Mega dropdown layout */
.dd-mega{width:min(880px,calc(100vw - 48px));left:50%}
.dd-mega-inner{display:grid;grid-template-columns:repeat(6,1fr);gap:0;padding:18px 14px 14px}
.dd-col{padding:6px 8px;border-right:1px solid var(--br)}
.dd-col:last-child{border-right:none}
.dd-cat-hd{display:flex;align-items:center;gap:7px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid var(--br)}
.dd-cat-ico{width:26px;height:26px;border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0;border:1px solid transparent}
.dd-cat-nm{font-size:11.5px;font-weight:800;color:var(--tx);letter-spacing:-.1px;line-height:1.2}
.dd-tool{display:block;padding:5px 6px;border-radius:7px;font-size:12px;color:var(--t2);text-decoration:none;transition:all .15s;white-space:nowrap}
.dd-tool:hover{background:rgba(59,130,246,.08);color:var(--tx);padding-left:10px}
.dd-mega-ft{border-top:1px solid var(--br);padding:10px 14px}
.dd-mega-all{display:flex;align-items:center;justify-content:center;padding:10px 20px;border-radius:10px;background:rgba(59,130,246,.07);border:1px solid rgba(59,130,246,.18);color:#60a5fa;font-size:13px;font-weight:700;text-decoration:none;transition:all .2s}
.dd-mega-all:hover{background:rgba(59,130,246,.14);border-color:rgba(59,130,246,.35);color:#93c5fd}
/* Responsive: hide mega on small screens, keep items accessible via mobile nav */
@media(max-width:1100px){.dd-mega{min-width:680px}.dd-mega-inner{grid-template-columns:repeat(3,1fr)}.dd-col{border-right:none;border-bottom:1px solid var(--br)}.dd-col:last-child{border-bottom:none}}
/* legacy di/d-ico/d-n classes kept for compatibility */
.di{display:flex;align-items:center;gap:10px;padding:9px 11px;border-radius:10px;text-decoration:none;color:var(--t2);transition:all .15s}
.di:hover{background:var(--s3);color:var(--tx)}
.d-ico{width:34px;height:34px;border-radius:9px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:16px}
.d-n{font-size:12.5px;font-weight:600;color:var(--tx);line-height:1.2}
.d-d{font-size:10.5px;color:var(--t3);margin-top:1px}
.dh{padding:5px 12px 3px;font-size:10px;font-weight:800;letter-spacing:1.5px;text-transform:uppercase;color:var(--t3)}
/* HEADER RIGHT */
.hdr-r{display:flex;align-items:center;gap:8px;margin-left:auto;flex-shrink:0}
.h-srch{display:flex;align-items:center;gap:6px;padding:7px 14px;border-radius:50px;background:var(--s3);border:1px solid var(--br);color:var(--t2);font-size:13px;cursor:pointer;transition:all .2s;font-family:var(--f-body);position:relative;overflow:hidden}
.h-srch::after{content:'';position:absolute;inset:-2px;background:linear-gradient(120deg,transparent 0 35%,rgba(96,165,250,.22),transparent 65%);transform:translateX(-140%);animation:srchSweep 4.5s ease-in-out infinite;pointer-events:none}
.h-srch:hover,.h-srch:focus{border-color:var(--a);color:var(--a);box-shadow:0 0 0 4px rgba(59,130,246,.1);outline:none}
@keyframes srchSweep{0%,55%{transform:translateX(-140%)}78%,100%{transform:translateX(140%)}}
.th-btn{width:36px;height:36px;border-radius:10px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:16px;transition:all .2s}
.th-btn:hover{border-color:var(--a);color:var(--a)}
.h-cta{background:var(--grad);color:#fff;padding:9px 20px;border-radius:50px;font-size:13px;font-weight:700;text-decoration:none;box-shadow:0 4px 14px rgba(59,130,246,.35);transition:all .2s}
.h-cta:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(59,130,246,.5);color:#fff}
.mob-btn{display:none;width:36px;height:36px;border-radius:10px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;align-items:center;justify-content:center;flex-direction:column;gap:5px}
.mob-btn span{display:block;width:18px;height:2px;background:currentColor;border-radius:2px}

/* ━━ MOBILE NAV ━━ */
.mob-nav{display:none;position:fixed;inset:0;z-index:1500;background:rgba(0,0,0,.76);backdrop-filter:blur(14px)}
.mob-nav.open{display:flex;animation:fadeIn .2s}
.mob-inner{width:min(320px,88vw);height:100vh;background:var(--s1);border-right:1px solid var(--br2);display:flex;flex-direction:column;animation:slideL .3s var(--ease);box-shadow:24px 0 60px rgba(0,0,0,.4)}
@keyframes slideL{from{transform:translateX(-100%)}to{transform:translateX(0)}}
.mob-hd{display:flex;align-items:center;justify-content:flex-end;padding:14px 16px;border-bottom:1px solid var(--br);flex-shrink:0}
.mob-cl{width:30px;height:30px;border-radius:8px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:14px;transition:all .15s}
.mob-cl:hover{background:var(--s4);color:var(--tx)}
.mob-list{flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;overscroll-behavior:contain;padding:8px 0}
.mob-sec{font-size:9px;font-weight:800;letter-spacing:1.8px;text-transform:uppercase;color:var(--t3);padding:16px 18px 6px}
.mob-lnk{display:flex;align-items:center;gap:11px;padding:9px 18px;font-size:13.5px;color:var(--t2);text-decoration:none;transition:all .15s;border-left:2px solid transparent}
.mob-lnk:hover{background:var(--s2);color:var(--tx);border-left-color:var(--a);padding-left:20px}
.mob-ico{width:30px;height:30px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0;background:var(--s3);border:1px solid var(--br)}
.mob-div{height:1px;background:var(--br);margin:6px 14px}
.mob-foot{flex-shrink:0;padding:14px 18px 28px;border-top:1px solid var(--br)}
.mob-cta{display:flex;align-items:center;justify-content:center;gap:8px;padding:11px 22px;border-radius:50px;font-size:13.5px;font-weight:700;text-decoration:none;background:var(--grad);color:#fff!important;box-shadow:0 4px 16px rgba(59,130,246,.3);transition:all .2s}
.mob-cta:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(59,130,246,.45)}

/* ━━ SEARCH OVERLAY ━━ */
.s-ov{display:none;position:fixed;inset:0;z-index:2000;background:rgba(0,0,0,.85);backdrop-filter:blur(16px);align-items:flex-start;justify-content:center;padding-top:80px}
.s-ov.open{display:flex;animation:fadeIn .2s}
.s-box{width:min(640px,calc(100% - 40px));background:var(--s1);border:1px solid var(--br2);border-radius:var(--r3);overflow:hidden;box-shadow:0 32px 80px rgba(0,0,0,.6);transform:translateY(18px) scale(.96);opacity:0}
.s-ov.open .s-box{animation:searchPop .32s var(--ease) forwards}
@keyframes searchPop{to{transform:translateY(0) scale(1);opacity:1}}
.s-row{display:flex;align-items:center;padding:0 20px;border-bottom:1px solid var(--br)}
.s-row span{font-size:19px;flex-shrink:0}
.s-inp{flex:1;padding:17px 12px;background:transparent;border:none;outline:none;font-size:17px;color:var(--tx);font-family:var(--f-body)}
.s-inp::placeholder{color:var(--t3)}
.s-cls{width:32px;height:32px;border-radius:8px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:13px}
.s-hints{padding:14px 20px;font-size:12px;color:var(--t3);display:flex;gap:8px;flex-wrap:wrap;align-items:center}
.s-tag{padding:4px 11px;border-radius:50px;background:var(--s3);border:1px solid var(--br);color:var(--t2);cursor:pointer;font-size:12px;font-weight:500;transition:all .18s;font-family:var(--f-body)}
.s-tag:hover{border-color:var(--a);color:var(--a)}

/* ━━ SECTION TRANSITIONS ━━ */
.feats{padding:88px 0;background:linear-gradient(180deg,var(--bg) 0,var(--bg2) 80px)}
.cta-s{padding:88px 0;background:linear-gradient(180deg,var(--bg2) 0,var(--bg) 80px)}

/* ━━ HERO ━━ */
.hero{position:relative;overflow:hidden;padding:112px 0 104px;background:var(--bg2)}
.hero-bg{position:absolute;inset:0;pointer-events:none;background:radial-gradient(ellipse at 15% 25%,rgba(59,130,246,.18) 0,transparent 55%),radial-gradient(ellipse at 85% 75%,rgba(99,102,241,.15) 0,transparent 50%),radial-gradient(ellipse at 55% 5%,rgba(34,211,238,.1) 0,transparent 42%)}
body.light-mode .hero-bg{background:radial-gradient(ellipse at 15% 25%,rgba(37,99,235,.07) 0,transparent 55%),radial-gradient(ellipse at 85% 75%,rgba(79,70,229,.05) 0,transparent 50%)}
.hero-dots{position:absolute;inset:0;pointer-events:none;opacity:.22;background-image:radial-gradient(circle,var(--br2) 1px,transparent 1px);background-size:28px 28px;animation:dotDrift 90s linear infinite}
@keyframes dotDrift{from{background-position:0 0}to{background-position:560px 560px}}
.orb{position:absolute;border-radius:50%;filter:blur(72px);pointer-events:none}
.o1{width:500px;height:500px;background:rgba(59,130,246,.1);top:-150px;left:-100px;animation:ob1 14s ease-in-out infinite}
.o2{width:380px;height:380px;background:rgba(99,102,241,.09);bottom:-80px;right:-60px;animation:ob2 11s ease-in-out infinite}
.o3{width:240px;height:240px;background:rgba(34,211,238,.07);top:38%;right:10%;animation:ob3 16s ease-in-out infinite}
@keyframes ob1{0%,100%{transform:translate(0,0)}50%{transform:translate(40px,-50px)}}
@keyframes ob2{0%,100%{transform:translate(0,0)}50%{transform:translate(-30px,40px)}}
@keyframes ob3{0%,100%{transform:translate(0,0)}50%{transform:translate(25px,-30px)}}
.hero-cnt{position:relative;z-index:2;text-align:center}
.h-badge{display:inline-flex;align-items:center;gap:8px;padding:7px 18px;border-radius:50px;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.25);font-size:12px;font-weight:700;color:#60a5fa;letter-spacing:.4px;margin-bottom:28px;animation:fuP .6s .1s both,glow 3.5s ease-in-out 1.5s infinite}
.bdot{width:6px;height:6px;border-radius:50%;background:#60a5fa;animation:bl 1.4s ease-in-out infinite}
@keyframes bl{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.2;transform:scale(.65)}}
.h-title{font-family:var(--f-display);font-size:clamp(38px,7vw,70px);font-weight:800;letter-spacing:-2.5px;line-height:1.05;color:var(--tx);margin-bottom:22px;animation:fuP .7s .2s both}
.gt{background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.h-sub{font-size:17px;color:var(--t2);max-width:580px;margin:0 auto 44px;line-height:1.8;animation:fuP .7s .3s both}
.hs-wrap{max-width:660px;margin:0 auto 52px;animation:fuP .7s .4s both}
.hs-o{position:relative}
.hs-glow{position:absolute;inset:-2px;border-radius:60px;background:var(--grad);opacity:.16;filter:blur(14px);z-index:0;pointer-events:none;transition:opacity .4s var(--ease);animation:heroSearchGlow 3.8s ease-in-out infinite}
@keyframes heroSearchGlow{0%,100%{opacity:.12;transform:scale(.985)}50%{opacity:.28;transform:scale(1.01)}}
.hs-o.fc .hs-glow{opacity:.32}
.hs-i{position:relative;z-index:1;display:flex;align-items:center;background:var(--s1);border:1.5px solid var(--br2);border-radius:54px;padding:7px 7px 7px 22px;box-shadow:0 8px 40px rgba(0,0,0,.2);transition:border-color .35s}
.hs-o.fc .hs-i{border-color:rgba(99,130,246,.7);box-shadow:0 8px 40px rgba(0,0,0,.22),0 0 0 5px rgba(59,130,246,.12)}
.hs-icw{display:flex;align-items:center;justify-content:center;color:var(--t3);flex-shrink:0;margin-right:4px;transition:color .3s}
.hs-o.fc .hs-icw{color:var(--a)}
.hs-inp{flex:1;background:transparent;border:none;outline:none;font-family:var(--f-body);font-size:15px;color:var(--tx);padding:11px 12px;min-width:0;caret-color:var(--a)}
.hs-inp::placeholder{color:var(--t3)}
.hs-btn{display:flex;align-items:center;gap:7px;flex-shrink:0;padding:12px 26px;border-radius:50px;background:var(--grad);border:none;color:#fff;font-family:var(--f-body);font-size:14px;font-weight:700;cursor:pointer;box-shadow:0 4px 18px rgba(59,130,246,.35);transition:all .25s var(--ease)}
.hs-btn:hover{transform:scale(1.05);box-shadow:0 8px 28px rgba(59,130,246,.55)}
.hs-tags{display:flex;align-items:center;gap:8px;margin-top:14px;flex-wrap:wrap;justify-content:center}
.hs-hint{font-size:12px;color:var(--t3)}
.hs-stag{padding:5px 14px;border-radius:50px;background:rgba(255,255,255,.05);border:1px solid var(--br);color:var(--t2);font-size:12px;font-weight:600;cursor:pointer;font-family:var(--f-body);transition:all .2s}
.hs-stag:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08)}
body.light-mode .hs-stag{background:rgba(0,0,0,.03)}
.h-stats{display:flex;align-items:center;justify-content:center;gap:40px;flex-wrap:wrap;animation:fuP .7s .5s both}
.hs{text-align:center}
.hs-v{font-family:var(--f-display);font-size:28px;font-weight:800;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1}
.hs-l{font-size:12px;color:var(--t3);margin-top:4px}
.hs-sep{width:1px;height:40px;background:var(--br)}

/* ━━ SECTION HEADER ━━ */
.sh{text-align:center;margin-bottom:56px}
.sh-tag{display:inline-flex;align-items:center;gap:6px;padding:5px 16px;border-radius:50px;background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.25);font-size:11px;font-weight:700;color:var(--a3);letter-spacing:.6px;text-transform:uppercase;margin-bottom:14px}
.sh-t{font-family:var(--f-display);font-size:clamp(26px,4vw,42px);font-weight:800;letter-spacing:-1.2px;color:var(--tx);line-height:1.12;margin-bottom:12px}
.sh-s{font-size:15.5px;color:var(--t2);max-width:500px;margin:0 auto;line-height:1.8}

/* ━━ FEATURES ━━ */
.feats{padding:96px 0;background:var(--bg2);border-top:1px solid var(--br)}
.feat-g{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:20px}
.feat-card{padding:34px 28px 30px;border-radius:var(--r2);background:var(--s1);border:1px solid var(--br);position:relative;overflow:hidden;transition:transform .4s var(--ease),box-shadow .4s var(--ease),border-color .3s}
.feat-card::after{content:'';position:absolute;bottom:0;left:0;right:0;height:3px;background:var(--grad);transform:scaleX(0);transform-origin:left;transition:transform .45s var(--ease)}
.feat-card:hover{transform:translateY(-10px);box-shadow:0 24px 56px rgba(0,0,0,.22);border-color:rgba(59,130,246,.28)}
.feat-card:hover::after{transform:scaleX(1)}
.fi{width:58px;height:58px;border-radius:16px;display:flex;align-items:center;justify-content:center;font-size:24px;margin-bottom:20px;background:linear-gradient(135deg,rgba(59,130,246,.18),rgba(99,102,241,.08));border:1px solid rgba(59,130,246,.25)}
.ft{font-family:var(--f-display);font-size:17px;font-weight:700;color:var(--tx);margin-bottom:9px;letter-spacing:-.2px}
.fd{font-size:13.5px;color:var(--t2);line-height:1.78}


/* ━━ TOOL LIBRARY SHOWCASE ━━ */
.tool-lib{padding:96px 0;background:linear-gradient(180deg,var(--bg2),var(--bg));border-top:1px solid var(--br);position:relative;overflow:hidden}
.tool-lib::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 15% 15%,rgba(59,130,246,.08),transparent 30%),radial-gradient(circle at 85% 75%,rgba(34,211,238,.06),transparent 32%);pointer-events:none}
.tl-grid{position:relative;z-index:1;display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:18px}
.tl-card{display:flex;gap:14px;padding:22px;border-radius:var(--r2);background:var(--s1);border:1px solid var(--br);text-decoration:none;color:var(--tx);position:relative;overflow:hidden;transition:transform .25s var(--ease),border-color .25s,box-shadow .25s}
.tl-card::after{content:'';position:absolute;inset:0;background:linear-gradient(120deg,transparent 0 42%,rgba(255,255,255,.08),transparent 58%);transform:translateX(-120%);transition:transform .6s var(--ease)}
.tl-card:hover{transform:translateY(-6px);border-color:rgba(59,130,246,.38);box-shadow:0 18px 44px rgba(0,0,0,.18);color:var(--tx)}
.tl-card:hover::after{transform:translateX(120%)}
.tl-ico{width:48px;height:48px;border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;background:linear-gradient(135deg,rgba(59,130,246,.18),rgba(99,102,241,.08));border:1px solid rgba(59,130,246,.22)}
.tl-name{font-family:var(--f-display);font-size:16px;font-weight:800;color:var(--tx);margin-bottom:6px}
.tl-desc{font-size:13px;color:var(--t2);line-height:1.65;margin-bottom:10px}
.tl-mini{display:flex;flex-wrap:wrap;gap:6px}
.tl-mini span{font-size:11px;color:var(--t3);background:var(--s3);border:1px solid var(--br);border-radius:999px;padding:3px 8px}

/* ━━ AD AREAS (professional ad slots) ━━ */
.ad-banner{padding:12px 0;text-align:center}
.ad-banner-inner{max-width:970px;margin:0 auto;padding:0 24px}
.ad-slot{min-height:90px;background:var(--s2);border:1px dashed var(--br2);border-radius:var(--r1);display:flex;align-items:center;justify-content:center;font-size:12px;color:var(--t3);font-weight:600;letter-spacing:.5px}

/* ━━ BLOG PREVIEW (Homepage) ━━ */
.bp-sec{padding:96px 0;border-top:1px solid var(--br)}
.bp-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:22px}
.bp-card{border-radius:var(--r2);background:var(--s1);border:1px solid var(--br);overflow:hidden;display:flex;flex-direction:column;transition:transform .4s var(--ease),box-shadow .4s,border-color .3s;text-decoration:none;color:inherit}
.bp-card:hover{transform:translateY(-8px);box-shadow:0 24px 56px rgba(0,0,0,.22);border-color:rgba(59,130,246,.28)}
.bp-img{width:100%;height:180px;background:linear-gradient(135deg,var(--s3),var(--s4));display:flex;align-items:center;justify-content:center;overflow:hidden}
.bp-img img{width:100%;height:180px;object-fit:cover}
.bp-fb{font-size:40px}
.bp-body{padding:18px 20px 16px;flex:1;display:flex;flex-direction:column}
.bp-m{display:flex;align-items:center;gap:8px;margin-bottom:9px;flex-wrap:wrap}
.bp-cat{padding:3px 10px;border-radius:50px;font-size:10px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.2);color:#60a5fa}
.bp-dt{font-size:11.5px;color:var(--t3)}
.bp-tit{font-family:var(--f-display);font-size:15.5px;font-weight:700;color:var(--tx);line-height:1.35;margin-bottom:8px;letter-spacing:-.2px}
.bp-exc{font-size:13px;color:var(--t2);line-height:1.75;flex:1;margin-bottom:13px}
.bp-ft{display:flex;align-items:center;justify-content:space-between;border-top:1px solid var(--br);padding-top:11px}
.bp-au{display:flex;align-items:center;gap:7px}
.bp-av{width:26px;height:26px;border-radius:50%;background:var(--grad);display:flex;align-items:center;justify-content:center;font-size:12px;flex-shrink:0}
.bp-aun{font-size:12px;font-weight:600;color:var(--t2)}
.bp-rd{font-size:12px;color:var(--a);font-weight:600}
.bp-more{text-align:center;margin-top:44px}
.bp-btn{display:inline-flex;align-items:center;gap:8px;padding:13px 30px;border-radius:50px;border:1.5px solid var(--br2);background:var(--s1);color:var(--t2);font-size:14px;font-weight:600;text-decoration:none;transition:all .25s}
.bp-btn:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.06)}

/* ━━ CTA ━━ */
.cta-s{padding:96px 0;background:var(--bg2);border-top:1px solid var(--br)}
.cta-c{border-radius:var(--r3);background:linear-gradient(135deg,#0f2460 0%,#1e1b6b 45%,#0e1a38 100%);border:1px solid rgba(255,255,255,.08);padding:80px 40px;text-align:center;position:relative;overflow:hidden}
.cta-c::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse at 25% 55%,rgba(99,102,241,.28),transparent 58%),radial-gradient(ellipse at 75% 45%,rgba(34,211,238,.14),transparent 58%)}
.cta-in{position:relative;z-index:1}
.cta-badge{display:inline-flex;align-items:center;gap:6px;padding:5px 14px;border-radius:50px;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.14);font-size:11px;font-weight:700;color:rgba(255,255,255,.7);letter-spacing:.5px;text-transform:uppercase;margin-bottom:18px}
.cta-t{font-family:var(--f-display);font-size:clamp(28px,4.5vw,48px);font-weight:800;color:#fff;letter-spacing:-1.5px;margin-bottom:14px;line-height:1.1}
.cta-s2{font-size:16px;color:rgba(255,255,255,.6);max-width:480px;margin:0 auto 34px;line-height:1.7}
.cta-bs{display:flex;gap:12px;justify-content:center;flex-wrap:wrap}
.cb1{padding:14px 30px;border-radius:50px;background:linear-gradient(135deg,#60a5fa,#818cf8);color:#fff;font-weight:700;font-size:15px;text-decoration:none;box-shadow:0 6px 24px rgba(96,165,250,.42);display:inline-flex;align-items:center;gap:8px;transition:all .25s}
.cb1:hover{transform:translateY(-3px);box-shadow:0 14px 36px rgba(96,165,250,.55);color:#fff}
.cb2{padding:14px 24px;border-radius:50px;background:rgba(255,255,255,.1);border:1.5px solid rgba(255,255,255,.2);color:rgba(255,255,255,.8);font-weight:600;font-size:15px;text-decoration:none;display:inline-flex;align-items:center;gap:8px;transition:all .25s}
.cb2:hover{background:rgba(255,255,255,.18);color:#fff}

/* ━━ BLOG LISTING HERO ━━ */
.bl-hero{padding:68px 0 52px;background:var(--bg2);border-bottom:1px solid var(--br);position:relative;overflow:hidden}
.bl-hero-bg{position:absolute;inset:0;pointer-events:none;background:radial-gradient(ellipse at 20% 40%,rgba(59,130,246,.14) 0,transparent 52%),radial-gradient(ellipse at 80% 60%,rgba(99,102,241,.09) 0,transparent 48%)}
.bl-hero-inn{position:relative;z-index:1;animation:fuP .6s .1s both}
.bc{display:flex;align-items:center;gap:6px;font-size:13px;color:var(--t3);margin-bottom:18px;flex-wrap:wrap}
.bc a{color:var(--t3)}.bc a:hover{color:var(--a)}.bc span{color:var(--t4)}
.bl-tag{display:inline-flex;align-items:center;gap:6px;padding:5px 14px;border-radius:50px;background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.25);font-size:11px;font-weight:700;color:var(--a3);letter-spacing:.5px;text-transform:uppercase;margin-bottom:14px}
.bl-ht{font-family:var(--f-display);font-size:clamp(30px,5vw,50px);font-weight:800;letter-spacing:-1.5px;color:var(--tx);line-height:1.1;margin-bottom:12px}
.bl-hs{font-size:15.5px;color:var(--t2);max-width:520px;line-height:1.8}

/* ━━ BLOG MAIN AREA ━━ */
.bl-sec{padding:68px 0 96px}
.bl-lay{display:grid;grid-template-columns:1fr 292px;gap:36px;align-items:start}
.posts-list{display:flex;flex-direction:column;gap:22px}
#thp-feed-fallback{display:none}
.thp-feed-loading,.thp-feed-empty{padding:28px;border-radius:var(--r2);background:var(--s1);border:1px solid var(--br);color:var(--t2);text-align:center;font-size:14px}
.thp-feed-empty strong{display:block;color:var(--tx);font-family:var(--f-display);font-size:18px;margin-bottom:8px}

/* ━━ POST CARD ━━ */
.post-card{background:var(--s1);border:1px solid var(--br);border-radius:var(--r2);overflow:hidden;transition:transform .4s var(--ease),box-shadow .4s,border-color .3s}
.post-card:hover{transform:translateY(-6px);box-shadow:0 20px 48px rgba(0,0,0,.22);border-color:rgba(59,130,246,.25)}
.pc-img{width:100%;height:196px;background:linear-gradient(135deg,var(--s3),var(--s4));display:flex;align-items:center;justify-content:center;overflow:hidden}
.pc-img img{width:100%;height:196px;object-fit:cover}
.pc-body{padding:20px 22px 18px}
.pc-tags{display:flex;gap:6px;margin-bottom:11px;flex-wrap:wrap}
.pc-tag{padding:3px 10px;border-radius:50px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.2);color:#60a5fa;text-decoration:none}
.pc-tag:hover{background:rgba(59,130,246,.18)}
.pc-tit{font-family:var(--f-display);font-size:18px;font-weight:700;color:var(--tx);letter-spacing:-.3px;line-height:1.3;margin-bottom:9px}
.pc-tit a{color:var(--tx)}.pc-tit a:hover{color:var(--a)}
.pc-exc{font-size:13.5px;color:var(--t2);line-height:1.7;margin-bottom:14px}
.pc-meta{display:flex;align-items:center;gap:13px;font-size:12px;color:var(--t3);padding-top:13px;border-top:1px solid var(--br);flex-wrap:wrap}
.pmi{display:flex;align-items:center;gap:5px}
.prm{margin-left:auto;font-size:12.5px;font-weight:600;color:var(--a);text-decoration:none;display:flex;align-items:center;gap:4px}
.prm:hover{gap:7px}

/* ━━ SINGLE POST ━━ */
.p-s{max-width:760px}
.ps-hd{margin-bottom:30px}
.ps-t{font-family:var(--f-display);font-size:clamp(24px,4vw,40px);font-weight:800;letter-spacing:-1px;color:var(--tx);line-height:1.15;margin-bottom:14px}
.ps-m{display:flex;align-items:center;gap:14px;font-size:13px;color:var(--t3);flex-wrap:wrap;padding-bottom:18px;border-bottom:1px solid var(--br)}
.ps-fi{width:100%;border-radius:var(--r2);overflow:hidden;margin:22px 0;border:1px solid var(--br)}
.ps-fi img{width:100%}
.p-content{font-size:15.5px;line-height:1.88;color:var(--t2)}
.p-content h1,.p-content h2,.p-content h3,.p-content h4{font-family:var(--f-display);color:var(--tx);margin:30px 0 13px;font-weight:700;letter-spacing:-.3px;line-height:1.2}
.p-content h2{font-size:24px}.p-content h3{font-size:20px}
.p-content p{margin-bottom:17px}
.p-content a{color:var(--a);border-bottom:1px solid rgba(59,130,246,.3)}
.p-content a:hover{border-bottom-color:var(--a)}
.p-content ul,.p-content ol{margin:0 0 17px 22px}
.p-content li{margin-bottom:6px}
.p-content blockquote{margin:22px 0;padding:16px 20px;border-left:4px solid var(--a);background:rgba(59,130,246,.06);border-radius:0 var(--r1) var(--r1) 0;font-style:italic;color:var(--t2)}
.p-content code{background:var(--s3);padding:2px 7px;border-radius:5px;font-size:12.5px;color:var(--a3)}
.p-content pre{background:var(--s2);border:1px solid var(--br);border-radius:var(--r1);padding:18px;overflow-x:auto;margin:22px 0}
.p-content pre code{background:none;padding:0}
.p-content img{max-width:100%;border-radius:var(--r1);margin:16px 0}
.p-content table{width:100%;border-collapse:collapse;margin:22px 0;font-size:14px}
.p-content th,.p-content td{padding:11px 15px;border:1px solid var(--br);text-align:left}
.p-content th{background:var(--s3);font-weight:700;color:var(--tx)}
.p-tags{margin-top:34px;padding-top:18px;border-top:1px solid var(--br);display:flex;align-items:center;gap:8px;flex-wrap:wrap}
.p-tags span{font-size:12px;color:var(--t3)}

/* ━━ AUTHOR BOX ━━ */
.auth-box{display:flex;align-items:center;gap:18px;margin-top:38px;padding:22px 24px;border-radius:var(--r2);background:var(--s2);border:1px solid var(--br)}
.auth-av{width:60px;height:60px;border-radius:50%;background:var(--grad);display:flex;align-items:center;justify-content:center;font-size:26px;flex-shrink:0;border:3px solid var(--br2)}
.auth-name{font-family:var(--f-display);font-size:15px;font-weight:700;color:var(--tx);margin-bottom:5px}
.auth-bio{font-size:13px;color:var(--t2);line-height:1.65}

/* ━━ RELATED POSTS ━━ */
.rel-posts{margin-top:52px;padding-top:36px;border-top:1px solid var(--br)}
.rel-hd{font-family:var(--f-display);font-size:20px;font-weight:700;color:var(--tx);margin-bottom:22px;display:flex;align-items:center;gap:8px}
.rel-hd::before{content:'';width:4px;height:20px;background:var(--grad);border-radius:2px;flex-shrink:0;display:inline-block}

/* ━━ SIDEBAR ━━ */
.sidebar{position:sticky;top:calc(var(--nav-h) + 20px);display:flex;flex-direction:column;gap:18px}
.sw{background:var(--s1);border:1px solid var(--br);border-radius:var(--r2);overflow:hidden}
.sw-hd{padding:13px 17px;border-bottom:1px solid var(--br);font-family:var(--f-display);font-size:13.5px;font-weight:700;color:var(--tx);display:flex;align-items:center;gap:8px}
.sw-hd::before{content:'';width:3px;height:14px;background:var(--a);border-radius:2px;flex-shrink:0}
.sw-bd{padding:13px 17px}
/* Sidebar search */
.sw-search{display:flex;align-items:center;gap:0;background:var(--s3);border:1px solid var(--br);border-radius:50px;overflow:hidden;margin-bottom:4px}
.sw-sinp{flex:1;background:transparent;border:none;outline:none;padding:10px 14px;font-size:13px;color:var(--tx);font-family:var(--f-body)}
.sw-sinp::placeholder{color:var(--t3)}
.sw-sbtn{padding:8px 14px;background:var(--a);border:none;color:#fff;font-size:14px;cursor:pointer;flex-shrink:0;transition:background .2s}
.sw-sbtn:hover{background:var(--a2)}
/* Sidebar about */
.sw-about-img{width:60px;height:60px;border-radius:50%;background:var(--grad);display:flex;align-items:center;justify-content:center;font-size:26px;margin:0 auto 12px;border:3px solid var(--br2)}
.sw-about-nm{font-family:var(--f-display);font-size:15px;font-weight:700;color:var(--tx);text-align:center;margin-bottom:6px}
.sw-about-tx{font-size:12.5px;color:var(--t2);text-align:center;line-height:1.7;margin-bottom:14px}
.sw-about-soc{display:flex;justify-content:center;gap:8px}
.sw-sb{width:32px;height:32px;border-radius:9px;background:var(--s3);border:1px solid var(--br);display:flex;align-items:center;justify-content:center;font-size:13px;text-decoration:none;color:var(--t2);transition:all .2s}
.sw-sb:hover{border-color:var(--a);color:var(--a)}
/* Tool list */
.sw-tools{display:flex;flex-direction:column;gap:3px}
.sw-ti{display:flex;align-items:center;gap:9px;padding:8px 10px;border-radius:9px;text-decoration:none;color:var(--t2);transition:background .15s}
.sw-ti:hover{background:var(--s3);color:var(--tx)}
.sw-tico{width:30px;height:30px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0}
.sw-tnm{font-size:12.5px;font-weight:600}
.sw-cta{display:flex;align-items:center;justify-content:center;gap:6px;padding:10px 20px;width:100%;margin-top:12px;border-radius:50px;background:var(--grad);color:#fff;font-size:13px;font-weight:700;text-decoration:none;box-shadow:0 4px 16px rgba(59,130,246,.3);transition:all .2s}
.sw-cta:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(59,130,246,.45);color:#fff}
/* Labels */
.lbl-cloud{display:flex;flex-wrap:wrap;gap:6px}
.lbl-lnk{display:inline-flex;align-items:center;padding:5px 12px;border-radius:50px;font-size:12px;font-weight:600;color:var(--t2);background:var(--s3);border:1px solid var(--br);text-decoration:none;transition:all .2s}
.lbl-lnk:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08)}
/* Newsletter */
.sw-nl p{font-size:13px;color:var(--t2);line-height:1.7;margin-bottom:12px}
.sw-nl-inp{display:flex;flex-direction:column;gap:8px}
.sw-nl-inp input{width:100%;padding:10px 14px;border-radius:10px;border:1px solid var(--br2);background:var(--s3);color:var(--tx);font-size:13px;font-family:var(--f-body);outline:none;transition:border-color .2s}
.sw-nl-inp input:focus{border-color:var(--a)}
.sw-nl-inp input::placeholder{color:var(--t3)}
.sw-nl-btn{padding:10px 20px;border-radius:10px;background:var(--grad);color:#fff;border:none;font-size:13px;font-weight:700;cursor:pointer;width:100%;font-family:var(--f-body);transition:all .2s}
.sw-nl-btn:hover{opacity:.9}
/* Popular posts (Blogger widget override) */
.popular-posts-widget .widget-content ul{list-style:none}
.popular-posts-widget .widget-content ul li{padding:9px 0;border-bottom:1px solid var(--br)}
.popular-posts-widget .widget-content ul li:last-child{border-bottom:none;padding-bottom:0}
.popular-posts-widget .widget-content ul li a{font-size:13px;font-weight:600;color:var(--tx);text-decoration:none;display:block;line-height:1.4}
.popular-posts-widget .widget-content ul li a:hover{color:var(--a)}
.popular-posts-widget .snippet-thumbnail{width:52px;height:52px;border-radius:8px;object-fit:cover;float:left;margin-right:10px;border:1px solid var(--br)}
.popular-posts-widget .item-title{overflow:hidden}
.popular-posts-widget .item-snippet{font-size:11.5px;color:var(--t3);margin-top:3px;display:block}
/* Archive widget */
#BlogArchive1 select,.BlogArchive .widget-content select{width:100%;padding:9px 12px;border-radius:10px;border:1px solid var(--br2);background:var(--s3);color:var(--tx);font-size:13px;font-family:var(--f-body);outline:none;cursor:pointer}
#BlogArchive1 ul,.BlogArchive .widget-content ul{list-style:none}
#BlogArchive1 ul li,.BlogArchive .widget-content ul li{padding:6px 0;font-size:13px;color:var(--t2);display:flex;align-items:center;justify-content:space-between}
#BlogArchive1 ul li a,.BlogArchive .widget-content ul li a{color:var(--t2);text-decoration:none;font-size:13px}
#BlogArchive1 ul li a:hover,.BlogArchive .widget-content ul li a:hover{color:var(--a)}

/* ━━ PAGINATION ━━ */
.pag{display:flex;align-items:center;justify-content:center;gap:6px;padding:44px 0 0;flex-wrap:wrap}
.pag a{min-width:40px;height:40px;padding:0 14px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:13.5px;font-weight:600;text-decoration:none;transition:all .2s;background:var(--s1);border:1px solid var(--br);color:var(--t2)}
.pag a:hover{border-color:var(--a);color:var(--a);background:var(--s3)}

/* ━━ FOOTER ━━ */
#lp-footer{background:var(--bg);position:relative;overflow:hidden}
#lp-footer::before{content:'';position:absolute;top:0;left:0;right:0;height:1px;background:var(--grad);opacity:.5}
#lp-footer::after{content:'';position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;background:radial-gradient(ellipse at 10% 0%,rgba(59,130,246,.06) 0,transparent 50%),radial-gradient(ellipse at 90% 100%,rgba(99,102,241,.05) 0,transparent 50%)}
.ft-top{padding:56px 0 48px;position:relative;z-index:1}
.ft-top-in{display:flex;align-items:flex-start;justify-content:space-between;gap:48px;flex-wrap:wrap}
.ft-brand{flex:0 0 300px;max-width:300px}
.ft-logo{display:flex;align-items:center;gap:10px;margin-bottom:14px;text-decoration:none}
.ft-logo-ico{width:40px;height:40px;border-radius:12px;background:linear-gradient(135deg,#1e40af,#4f46e5);border:1px solid rgba(99,102,241,.4);display:flex;align-items:center;justify-content:center;flex-shrink:0;box-shadow:0 4px 16px rgba(59,130,246,.28)}
.ft-logo-txt{font-family:var(--f-display);font-size:19px;font-weight:800;letter-spacing:-.4px;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.ft-tagline{font-size:13.5px;color:var(--t3);line-height:1.85;margin-bottom:22px}
.ft-soc{display:flex;gap:8px}
.ft-si{width:36px;height:36px;border-radius:10px;background:var(--s2);border:1px solid var(--br);display:flex;align-items:center;justify-content:center;color:var(--t2);text-decoration:none;transition:all .22s;flex-shrink:0}
.ft-si:hover{background:rgba(59,130,246,.1);border-color:rgba(59,130,246,.4);color:#60a5fa;transform:translateY(-2px)}
.ft-si svg{width:15px;height:15px}
.ft-cols{display:flex;gap:48px;flex-wrap:wrap}
.ft-col{}
.fc-tit{font-size:10.5px;font-weight:800;letter-spacing:1.8px;text-transform:uppercase;color:var(--t2);margin-bottom:18px;display:flex;align-items:center;gap:7px}
.fc-tit::after{content:'';flex:1;height:1px;background:var(--br);display:inline-block;min-width:20px}
.f-links{display:flex;flex-direction:column;gap:10px}
.f-lnk{font-size:13px;color:var(--t3);text-decoration:none;transition:all .18s;display:flex;align-items:center;gap:5px}
.f-lnk::before{content:'';width:4px;height:4px;border-radius:50%;background:var(--br2);flex-shrink:0;transition:all .18s}
.f-lnk:hover{color:var(--tx);transform:translateX(4px)}
.f-lnk:hover::before{background:var(--a)}
.ft-div{height:1px;background:linear-gradient(90deg,transparent,var(--br),transparent);margin:0;position:relative;z-index:1}
.ft-bot{padding:18px 0;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;position:relative;z-index:1}
.ft-copy{font-size:12px;color:var(--t3)}
.ft-bot-links{display:flex;gap:20px}
.ft-bot-links a{font-size:12px;color:var(--t3);text-decoration:none;transition:color .18s}
.ft-bot-links a:hover{color:var(--tx)}
@media(max-width:900px){.ft-top-in{flex-direction:column;gap:36px}.ft-brand{max-width:100%;flex:none}.ft-cols{gap:32px}}
@media(max-width:520px){.ft-cols{flex-direction:column;gap:28px}.ft-bot{flex-direction:column;align-items:flex-start;gap:12px}}

/* ━━ REVEAL ANIMATIONS ━━ */
@keyframes fuP{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:translateY(0)}}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes glow{0%,100%{box-shadow:0 0 0 0 rgba(59,130,246,0)}50%{box-shadow:0 0 0 14px rgba(59,130,246,.06)}}
.rv{opacity:1;transform:translateY(0) scale(1);animation:fuP .7s cubic-bezier(.22,1,.36,1) both}
.rv.d1{animation-delay:.07s}.rv.d2{animation-delay:.14s}.rv.d3{animation-delay:.21s}.rv.d4{animation-delay:.28s}
.rv.on{opacity:1;transform:translateY(0) scale(1)}


/* ━━ PARTICLES CANVAS ━━ */
canvas#hp-canvas{position:absolute;inset:0;pointer-events:none;opacity:.45}

/* ━━ RESPONSIVE ━━ */
@media(max-width:1024px){.foot-g{grid-template-columns:1fr 1fr}.bl-lay{grid-template-columns:1fr}.sidebar{position:static}}
@media(max-width:768px){.lp-nav{display:none}.mob-btn{display:flex}.h-srch{display:flex;width:36px;height:36px;padding:0;justify-content:center;border-radius:10px}.h-srch .srch-txt{display:none}.h-stats{gap:20px}.hs-sep{display:none}.cta-c{padding:56px 22px}.foot-g{grid-template-columns:1fr 1fr}.bp-grid{grid-template-columns:1fr}}
@media(max-width:480px){.foot-g{grid-template-columns:1fr}.hs-i{flex-direction:column;border-radius:20px;padding:14px;gap:10px}.hs-btn{width:100%;justify-content:center}.cta-bs{flex-direction:column;align-items:center}}
@media(prefers-reduced-motion:reduce){*,*::before,*::after{animation:none !important;transition:none !important}.rv{opacity:1;transform:none}}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   BLOGGER OVERRIDES — Prevents Blogger's
   default widget/gadget styles from
   overriding our theme. Keep at bottom.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
body{margin:0!important;padding:0!important}
.widget,.gadget{margin:0!important;padding:0!important;border:none!important;background:transparent!important}
.widget-content{margin:0!important;padding:0!important}
.widget h2,.widget-title,.gadget-title{margin:0!important;padding:0!important;font-family:var(--f-display)!important;font-size:inherit!important;font-weight:inherit!important;color:inherit!important;background:none!important;border:none!important;text-transform:none!important;letter-spacing:normal!important}
#blog-pager,.blog-pager{display:none}
.date-header{display:none!important}
.post-body{font-family:var(--f-body);font-size:15.5px;line-height:1.88;color:var(--t2)}
.post-body img{max-width:100%;height:auto;border-radius:var(--r1)}
.post-body ul,.post-body ol{margin:0 0 17px 22px}
.post-body li{margin-bottom:6px}
.post-body h1,.post-body h2,.post-body h3,.post-body h4{font-family:var(--f-display);color:var(--tx);margin:28px 0 12px;font-weight:700;letter-spacing:-.3px;line-height:1.2}
.post-body h2{font-size:24px}.post-body h3{font-size:20px}
.post-body p{margin-bottom:17px}
.post-body a{color:var(--a);border-bottom:1px solid rgba(59,130,246,.3);text-decoration:none}
.post-body a:hover{border-bottom-color:var(--a)}
.post-body blockquote{margin:22px 0;padding:16px 20px;border-left:4px solid var(--a);background:rgba(59,130,246,.06);border-radius:0 var(--r1) var(--r1) 0;font-style:italic;color:var(--t2)}
.post-body pre{background:var(--s2);border:1px solid var(--br);border-radius:var(--r1);padding:18px;overflow-x:auto;margin:22px 0}
.post-body code{background:var(--s3);padding:2px 7px;border-radius:5px;font-size:12.5px;color:var(--a3)}
.post-body pre code{background:none;padding:0}
.post-body table{width:100%;border-collapse:collapse;margin:22px 0;font-size:14px}
.post-body th,.post-body td{padding:11px 15px;border:1px solid var(--br);text-align:left}
.post-body th{background:var(--s3);font-weight:700;color:var(--tx)}
/* Blogger comment form */
#comments{margin-top:40px}
.comment-thread,.comment-form{font-family:var(--f-body);color:var(--t2);font-size:14px}
.comment-form textarea{width:100%;padding:10px 14px;border-radius:10px;border:1px solid var(--br2);background:var(--s3);color:var(--tx);font-size:14px;font-family:var(--f-body);outline:none;resize:vertical;min-height:100px}
.comment-form input[type=text],.comment-form input[type=url]{width:100%;padding:9px 14px;border-radius:10px;border:1px solid var(--br2);background:var(--s3);color:var(--tx);font-size:13px;font-family:var(--f-body);outline:none;margin-bottom:8px}
.comment-form input[type=submit]{padding:10px 22px;border-radius:50px;background:var(--grad);color:#fff;border:none;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--f-body);transition:opacity .2s}
.comment-form input[type=submit]:hover{opacity:.88}
/* Blogger bars — navbar, attribution, powered-by — completely hidden */
#navbar-iframe,#navbar,b-navbar,#b-navbar,.b-notification,
#Attribution1,.widget.Attribution,#google_esf,
.b-dnd-header,.b-dnd-footer,
.blogger-attribution,.blogger-navbar-bg,
div[class*='blogger-nav'],div[id*='navbar']{display:none!important;height:0!important;visibility:hidden!important;overflow:hidden!important;padding:0!important;margin:0!important}
/* Ad banner sections: zero padding when empty, JS will add has-widgets class */
.ad-banner{padding:0;text-align:center}
.ad-banner.has-widgets{padding:12px 0}
/* ── POST + LISTING LAYOUT ─────────────────── */
/* Single post: sticky sidebar */
body.page-item .sidebar{position:sticky;top:calc(var(--nav-h) + 20px)}
/* Announcement bar — only show when it has actual content */
.ann-bar-wrap:empty,.ann-bar-wrap>*:empty{display:none!important}
/* Blogger label/archive widgets alignment fix */
.label-list,.label-list-link{display:flex;flex-wrap:wrap;gap:6px;list-style:none;padding:0;margin:0}
.label-list li{display:inline}
.label-list li a{display:inline-flex;align-items:center;padding:5px 12px;border-radius:50px;font-size:12px;font-weight:600;color:var(--t2);background:var(--s3);border:1px solid var(--br);text-decoration:none;transition:all .2s}
.label-list li a:hover{border-color:var(--a);color:var(--a);background:rgba(59,130,246,.08)}
/* Ensure Blogger doesn't add unwanted margin to gadget sections */
.lp-section-wrap,.ann-bar-wrap,.ad-banner{overflow:visible}
/* svg icon base style */
.ico-svg{display:inline-flex;align-items:center;justify-content:center;flex-shrink:0}

b:if.script:
//
(function(){
  var blogUrl = '<data:blog.homepageUrl/>';
  var currentUrl = '<data:post.url/>';
  var firstLabel = '<data:post.labels[0].name/>';
  if(!firstLabel){ document.getElementById('rel-posts').style.display='none'; return; }
  var feed = blogUrl + 'feeds/posts/summary/-/' + encodeURIComponent(firstLabel) + '?alt=json&max-results=5&callback=_loadRel';
  window._loadRel = function(d){
    var entries = (d.feed && d.feed.entry) ? d.feed.entry : [];
    var grid = document.getElementById('rel-grid');
    if(!grid) return;
    var html = '';
    var count = 0;
    for(var i=0;i<entries.length;i++){
      if(count>=3) break;
      var e = entries[i];
      var link = '';
      for(var j=0;j<e.link.length;j++){if(e.link[j].rel==='alternate'){link=e.link[j].href;break;}}
      if(link===currentUrl) continue;
      var title = e.title.$t;
      var thumb = (e['media$thumbnail']&&e['media$thumbnail'].url) ? e['media$thumbnail'].url.replace(/\/s\d+-c\//,'/s400-c/') : '';
      var date = new Date(e.published.$t).toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'});
      var cat = (e.category&&e.category[0]) ? e.category[0].term : firstLabel;
      html += '<a class="bp-card" href="'+link+'">';
      html += '<div class="bp-img">'+(thumb?'<img src="'+thumb+'" alt="'+title+'">':'<div class="bp-fb">📰</div>')+'</div>';
      html += '<div class="bp-body">';
      html += '<div class="bp-m"><span class="bp-cat">'+cat+'</span><span class="bp-dt">'+date+'</span></div>';
      html += '<div class="bp-tit">'+title+'</div>';
      html += '<div class="bp-ft"><span class="bp-rd">Read more →</span></div>';
      html += '</div></a>';
      count++;
    }
    if(count>0){ grid.innerHTML=html; }
    else{ document.getElementById('rel-posts').style.display='none'; }
  };
  var s=document.createElement('script');
  s.src=feed;
  document.body.appendChild(s);
})();
//

body.script:
//
var THP_HOME='<data:blog.homepageUrl/>';
function thpUrl(path){return THP_HOME.replace(/\/?$/,'/')+String(path||'').replace(/^\//,'');}
function thpGoSearch(q){q=(q||'').trim();if(q){window.location.href=thpUrl('search?q='+encodeURIComponent(q));}}
function themeSearchFrom(id){var el=document.getElementById(id);thpGoSearch(el?el.value:'');}
function thpEsc(s){return String(s||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
function thpStrip(s){var d=document.createElement('div');d.innerHTML=s||'';return (d.textContent||d.innerText||'').replace(/\s+/g,' ').trim();}

/* ── Theme Switcher ── */
function _syncThIco(isLight){
  var moon=document.getElementById('ico-moon');
  var sun=document.getElementById('ico-sun');
  if(moon)moon.style.display=isLight?'none':'inline-block';
  if(sun)sun.style.display=isLight?'inline-block':'none';
}
(function(){
  var t=localStorage.getItem('th')||'dark';
  if(t==='light')document.body.classList.add('light-mode');
  _syncThIco(t==='light');
})();
function togTh(){
  var l=document.body.classList.toggle('light-mode');
  localStorage.setItem('th',l?'light':'dark');
  _syncThIco(l);
}

/* ── Mobile Nav ── */
function openM(){document.getElementById('mob-nav').classList.add('open');document.body.style.overflow='hidden';}
function closeM(){document.getElementById('mob-nav').classList.remove('open');document.body.style.overflow='';}

/* ── Search Overlay ── */
function openS(){
  document.getElementById('s-ov').classList.add('open');
  setTimeout(function(){var i=document.getElementById('s-inp');if(i)i.focus();},120);
}
function closeS(){document.getElementById('s-ov').classList.remove('open');}
function doS(){
  var v=(document.getElementById('s-inp')||{}).value||'';
  thpGoSearch(v);
}
function setS(q){
  var i=document.getElementById('s-inp');
  if(i){i.value=q;}
  openS();
}

/* ── Hero Search ── */
function setH(q){var el=document.getElementById('hero-inp');if(el){el.value=q;el.focus();}}
function hS(){
  var el=document.getElementById('hero-inp');
  var v=el?el.value.trim():'';
  thpGoSearch(v);
}
(function(){
  var el=document.getElementById('hero-inp');
  var o=document.getElementById('hs-o');
  if(!el||!o)return;
  el.addEventListener('focus',function(){o.classList.add('fc');});
  el.addEventListener('blur',function(){o.classList.remove('fc');});
  /* Typewriter */
  var ph=['Search from 100+ free tools...','Try "PDF Merger"...','Try "Image Converter"...','Try "Translator"...','Try "Calculator"...','Try "Password Generator"...'];
  var pi=0,ci=0,del=false;
  function ty(){
    if(document.activeElement===el)return;
    var p=ph[pi];
    if(!del){
      if(ci<=p.length){el.placeholder=p.slice(0,ci);ci++;setTimeout(ty,55);}
      else{setTimeout(function(){del=true;ty();},2200);}
    } else {
      if(ci>0){el.placeholder=p.slice(0,ci);ci--;setTimeout(ty,28);}
      else{del=false;pi=(pi+1)%ph.length;setTimeout(ty,400);}
    }
  }
  ty();
  el.addEventListener('blur',function(){setTimeout(ty,700);});
})();

/* ── Blogger upload fallback: keep brand text visible even if blog title is empty ── */
(function(){
  var names=document.querySelectorAll('.logo-txt,.ft-logo-txt');
  names.forEach(function(n){if(!(n.textContent||'').trim())n.textContent='ToolsHub Pro';});
})();

function thpFeedUrl(){
  var path=decodeURIComponent(location.pathname||'');
  var label='';
  var marker='/search/label/';
  if(path.indexOf(marker)>-1){label=path.split(marker)[1].split('/')[0];}
  var q='';
  try{q=new URLSearchParams(location.search).get('q')||'';}catch(e){}
  var base=label?thpUrl('feeds/posts/summary/-/'+encodeURIComponent(label)):thpUrl('feeds/posts/summary');
  var url=base+'?alt=json-in-script&max-results=9&callback=thpRenderFeedPosts';
  if(q){url+='&q='+encodeURIComponent(q);}
  return url;
}
window.thpRenderFeedPosts=function(d){
  var box=document.getElementById('thp-feed-fallback');
  if(!box)return;
  var entries=(d&&d.feed&&d.feed.entry)?d.feed.entry:[];
  if(!entries.length){
    box.innerHTML='<div class="thp-feed-empty"><strong>No posts found</strong><span>Publish posts in Blogger and keep the blog feed public to show them here.</span></div>';
    return;
  }
  var html='<div class="posts-list">';
  for(var i=0;i<entries.length;i++){
    var e=entries[i],link='',cat='';
    if(e.link){for(var j=0;j<e.link.length;j++){if(e.link[j].rel==='alternate'){link=e.link[j].href;break;}}}
    if(e.category&&e.category.length){cat=e.category[0].term||'';}
    var title=thpEsc(e.title&&e.title.$t?e.title.$t:'Untitled Post');
    var raw=e.summary&&e.summary.$t?e.summary.$t:(e.content&&e.content.$t?e.content.$t:'');
    var text=thpEsc(thpStrip(raw).slice(0,170));
    var date=e.published&&e.published.$t?new Date(e.published.$t).toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'}):'';
    var author=e.author&&e.author[0]&&e.author[0].name?e.author[0].name.$t:'Admin';
    var thumb=e['media$thumbnail']&&e['media$thumbnail'].url?e['media$thumbnail'].url.replace(/\/s\d+(-c)?\//,'/s640/'):'';
    html+='<article class="post-card">';
    html+='<div class="pc-img">'+(thumb?'<img src="'+thpEsc(thumb)+'" alt="'+title+'"/>':'<div style="display:flex;align-items:center;justify-content:center;height:100%;font-size:36px">📰</div>')+'</div>';
    html+='<div class="pc-body">';
    html+='<div class="pc-tags">'+(cat?'<span class="pc-tag">'+thpEsc(cat)+'</span>':'<span class="pc-tag">Blog</span>')+'</div>';
    html+='<div class="pc-tit"><a href="'+thpEsc(link)+'">'+title+'</a></div>';
    html+='<div class="pc-exc">'+text+(text.length>=170?'...':'')+'</div>';
    html+='<div class="pc-meta"><span class="pmi">📅 '+thpEsc(date)+'</span><span class="pmi">👤 '+thpEsc(author)+'</span><a class="prm" href="'+thpEsc(link)+'">Read more →</a></div>';
    html+='</div></article>';
  }
  html+='</div>';
  box.innerHTML=html;
};
(function(){
  function loadBlogFallback(){
    var box=document.getElementById('thp-feed-fallback');
    if(!box)return;
    var list=document.querySelector('.posts-list');
    var first=list?list.querySelector('.post-card .pc-tit a'):null;
    if(first&&(first.textContent||'').trim()){box.style.display='none';return;}
    box.style.display='block';
    box.innerHTML='<div class="thp-feed-loading">Loading latest posts...</div>';
    var old=document.getElementById('thp-feed-script');
    if(old&&old.parentNode){old.parentNode.removeChild(old);}
    var s=document.createElement('script');
    s.id='thp-feed-script';
    s.src=thpFeedUrl();
    s.onerror=function(){box.innerHTML='<div class="thp-feed-empty"><strong>Posts could not load</strong><span>Make sure Blogger Settings → Site feed is enabled and posts are public.</span></div>';};
    document.body.appendChild(s);
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){setTimeout(loadBlogFallback,500);});}
  else{setTimeout(loadBlogFallback,500);}
})();

/* ── Keyboard shortcuts ── */
document.addEventListener('keydown',function(e){
  if(e.key==='Escape'){closeS();closeM();}
  if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();openS();}
});

/* ── Header scroll effect ── */
window.addEventListener('scroll',function(){
  var h=document.getElementById('lp-header');
  if(h)h.classList.toggle('scr',window.scrollY>20);
},{passive:true});

/* ── Footer year ── */
var yr=document.getElementById('yr');
if(yr)yr.textContent=new Date().getFullYear();


/* ── Ensure rv elements near viewport are visible immediately ── */
(function(){
  document.querySelectorAll('.rv').forEach(function(el){
    var r=el.getBoundingClientRect();
    if(r.top&lt;window.innerHeight)el.classList.add('on');
  });
})();

/* ── Hide empty ad-banner and lp-section-wrap sections (prevents visible lines) ── */
(function(){
  function cleanEmpty(){
    document.querySelectorAll('.ad-banner,.lp-section-wrap').forEach(function(el){
      var txt=(el.textContent||'').trim();
      var hasIframe=el.querySelector('iframe');
      var hasImg=el.querySelector('img');
      if(!txt&&!hasIframe&&!hasImg){
        el.style.cssText='display:none!important;padding:0!important;margin:0!important;height:0!important;overflow:hidden!important;min-height:0!important';
      }
    });
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',cleanEmpty);}
  else{cleanEmpty();}
  setTimeout(cleanEmpty,600);
  window.addEventListener('load',cleanEmpty);
})();

/* ── Hide Blogger navbar completely ── */
(function(){
  var nb=document.getElementById('navbar-iframe');
  if(nb){nb.style.display='none';}
  document.querySelectorAll('iframe').forEach(function(f){
    if(f.id==='navbar-iframe'||f.src&&f.src.indexOf('blogger.com/navbar')>-1){
      f.style.cssText='display:none!important;height:0!important;';
    }
  });
})();

/* ── Scroll reveal (IntersectionObserver) ── */
(function(){
  var els=document.querySelectorAll('.rv');
  if(!('IntersectionObserver' in window)){
    els.forEach(function(el){el.classList.add('on');});
    return;
  }
  var obs=new IntersectionObserver(function(entries){
    entries.forEach(function(en){
      if(en.isIntersecting){en.target.classList.add('on');obs.unobserve(en.target);}
    });
  },{threshold:0.05,rootMargin:'0px 0px 0px 0px'});
  els.forEach(function(el){obs.observe(el);});
  setTimeout(function(){
    els.forEach(function(el){
      var r=el.getBoundingClientRect();
      if(r.top&lt;window.innerHeight&amp;&amp;r.bottom&gt;0)el.classList.add('on');
    });
  },150);
})();

/* ── Hero counter animation ── */
function easeOut(t){return 1-Math.pow(1-t,3);}
function animCnt(el,target,sfx,dur){
  if(!el)return;
  var start=performance.now();
  (function frame(now){
    var p=Math.min((now-start)/dur,1);
    el.textContent=Math.round(easeOut(p)*target)+sfx;
    if(p<1)requestAnimationFrame(frame);
  })(start);
}
window.addEventListener('load',function(){
  setTimeout(function(){
    animCnt(document.getElementById('hv1'),100,'+',1800);
    animCnt(document.getElementById('hv2'),12,'',1100);
  },500);
});

/* ── Particle canvas ── */
(function(){
  var c=document.getElementById('hp-canvas');
  if(!c)return;
  var ctx=c.getContext('2d');
  var W,H,pts=[];
  function resize(){
    var hero=c.parentElement;
    W=c.width=hero?hero.offsetWidth:window.innerWidth;
    H=c.height=hero?hero.offsetHeight:480;
    if(!W)W=window.innerWidth;
    if(!H)H=480;
  }
  window.addEventListener('resize',resize,{passive:true});
  resize();
  for(var i=0;i&lt;55;i++){
    pts.push({x:Math.random()*W,y:Math.random()*H,vx:(Math.random()-.5)*.3,vy:(Math.random()-.5)*.3,r:Math.random()*1.8+.4,a:Math.random()*.5+.1});
  }
  (function draw(){
    ctx.clearRect(0,0,W,H);
    for(var i=0;i&lt;pts.length;i++){
      var p=pts[i];
      p.x+=p.vx;p.y+=p.vy;
      if(p.x&lt;0||p.x&gt;W)p.vx*=-1;
      if(p.y&lt;0||p.y&gt;H)p.vy*=-1;
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle='rgba(99,130,246,'+p.a+')';ctx.fill();
      for(var j=i+1;j&lt;pts.length;j++){
        var q=pts[j],dx=p.x-q.x,dy=p.y-q.y,d=Math.sqrt(dx*dx+dy*dy);
        if(d&lt;120){ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(q.x,q.y);ctx.strokeStyle='rgba(99,130,246,'+(.1*(1-d/120))+')';ctx.lineWidth=.7;ctx.stroke();}
      }
    }
    requestAnimationFrame(draw);
  })();
})();
//
